SELECT path_loss
FROM path_loss_calculations
WHERE profile_id = 1 AND condition_id = 1 AND antenna_id = 0 AND model_id = 1;

SELECT profile_name, land_cover
FROM terrain_profiles
WHERE land_cover = 'urban' OR land_cover = 'suburban';

SELECT timestamp
FROM analysis_results
WHERE result_id = 'specific_result_id' AND accuracy > 90;

SELECT terrain_profiles.profile_name
FROM path_loss_calculations
JOIN terrain_profiles ON path_loss_calculations.profile_id = terrain_profiles.profile_id;

SELECT path_loss 
FROM path_loss_calculations 
WHERE calculation_id = 0;

SELECT profile_name, elevation, land_cover, obstacles, latitude, longitude, area
FROM terrain_profiles
WHERE profile_id = 1;

SELECT COUNT(*)
FROM atmospheric_conditions
WHERE wind_direction = 'North';

SELECT temperature, precipitation
FROM atmospheric_conditions
WHERE temperature > 20 AND precipitation < 5;

SELECT u.username, p.project_name
FROM users u
INNER JOIN projects p ON u.username = p.project_leader;

SELECT antenna_id, frequency, gain, antenna_type
FROM antenna_characteristics
WHERE gain > 5;

SELECT AVG(path_loss) 
FROM path_loss_calculations 
WHERE model_id = 1;

SELECT profile_name, latitude, longitude, elevation, land_cover, 
       DENSE_RANK() OVER (ORDER BY elevation DESC) as elevation_rank
FROM terrain_profiles;

SELECT DISTINCT profile_name 
FROM terrain_profiles
WHERE elevation > 1000;
